import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void targetInRightSegmentAfterRotation() {
        // [4,5,6,7,0,1,2] — 0 is in the right (unordered) segment at index 4
        assertEquals(4, new Solution().searchRotated(new int[]{4, 5, 6, 7, 0, 1, 2}, 0));
    }

    @Test
    void targetInLeftSegmentAfterRotation() {
        // [4,5,6,7,0,1,2] — 6 is in the left (sorted) segment at index 2
        assertEquals(2, new Solution().searchRotated(new int[]{4, 5, 6, 7, 0, 1, 2}, 6));
    }

    @Test
    void targetNotPresent() {
        assertEquals(-1, new Solution().searchRotated(new int[]{4, 5, 6, 7, 0, 1, 2}, 3));
    }

    @Test
    void singleElementMatch() {
        assertEquals(0, new Solution().searchRotated(new int[]{1}, 1));
    }

    @Test
    void emptyArray() {
        assertEquals(-1, new Solution().searchRotated(new int[]{}, 5));
    }

    @Test
    void twoElementRotated() {
        // [3,1] — rotated from [1,3], target=1 at index 1
        assertEquals(1, new Solution().searchRotated(new int[]{3, 1}, 1));
    }

    @Test
    void noRotationFullySorted() {
        // A sorted array with pivot at index 0 behaves like classic binary search
        assertEquals(3, new Solution().searchRotated(new int[]{1, 2, 3, 4, 5}, 4));
    }
}
